template_code:
Type Noeud = Enregistrement
Debut
    valeur  : Entier;
    suivant : ^Noeud;
Fin;

Algorithme Solution_09_Detection_Cycle;
Var
    tete, lent, rapide, liste[1000] : ^Noeud;
    Val[1000], index[1000]          : Entier;
    N, i                            : Entier;
    cycle                           : Booleen;
Debut
    Lire(N);

    Pour i := 0 a N - 1 Faire
        Lire(Val[i]);
    FinPour

    Pour i := 0 a N - 1 Faire
        Lire(index[i]);
    FinPour

    // 1) Creation des noeuds
    Pour i := 0 a N - 1 Faire
        liste[i] := allouer(Taille(Noeud));
        liste[i]->valeur := Val[i];
    FinPour

    // 2) Etablissement des liens
    Pour i := 0 a N - 1 Faire
        Si index[i] = -1 Alors
            liste[i]->suivant := NIL;
        Sinon
            liste[i]->suivant := liste[index[i]];
        FinSi;
    FinPour

    tete := liste[0];
    cycle := Faux;

    // 3) Detection (lièvre/tortue)
    Si tete <> NIL Alors
        lent := tete;
        rapide := tete;

        TantQue rapide <> NIL ET rapide->suivant <> NIL ET Non cycle Faire
            lent := lent->suivant;
            rapide := rapide->suivant->suivant;
            Si lent = rapide Alors
                cycle := Vrai;
            FinSi;
        FinTantQue
    FinSi

    Si cycle Alors
        Ecrire("Cycle");
    Sinon
        Ecrire("No Cycle");
    FinSi
Fin.
